import numpy as np
from dataclasses import dataclass

@dataclass
class HardwareParams:
    single_qubit_error: float
    two_qubit_error: float
    measurement_error: float

def find_supremacy_threshold(hardware: HardwareParams, classical_flops: float = 1e18, time_limit: float = 3600, target_xeb: float = 0.002) -> dict:
    max_ops = classical_flops * time_limit
    for n in range(40, 150):
        for d in range(10, 50):
            n_gates = n * d * 2
            xeb = ((1 - hardware.single_qubit_error) ** (n * d) * 
                   (1 - hardware.two_qubit_error) ** (n * d // 2) *
                   (1 - hardware.measurement_error) ** n)
            cost = 2 ** min(n, d) * n * d
            if xeb >= target_xeb and cost > max_ops:
                return {'threshold_qubits': n, 'optimal_depth': d, 'achievable_xeb': xeb}
    return {'threshold_qubits': None}
